<template>
	<view class="page">
		<status-bar />
		<scroll-view @touchmove.stop :scroll-y="true" class="scroll_content" :rebound="false"
			:style="{height:scrollHeight+'px'}" @scrolltolower="lower">
			<view class="header">
				<view class="bg" :style="{backgroundImage:`url(${$util.img('/statics/uni/img/news/top.jpg')})`}"></view>
				<view class="content">
					<view class="back" @click="$util.back()">
						<u-icon name="arrow-left-double"></u-icon>
					</view>
					<text class="t1">新品发布</text>
					<text class="t2">近期上架商品通知</text>
				</view>
			</view>
			<today-goods-list :list="list" />
			<u-loadmore :status="loading" icon-type="circle" @loadmore="fetchData" v-show="list.length" />
		</scroll-view>
	</view>
</template>

<script>
	import TodayGoodsList from './components/today-goods-list'
	import StatusBar from '@/components/my-page-header/status-bar'
	import {
		mapGetters
	} from 'vuex'
	export default {
		components: {
			'today-goods-list': TodayGoodsList,
			'status-bar': StatusBar,
		},
		data() {
			return {
				scrollHeight: 0,

				queryForm: {
					page: 1,
					limit: 10,
				},

				list: [], //卡组列表
				total: 0,
				loading: 'loadmore',
			};
		},
		computed: {
			...mapGetters(['deviceInfo'])
		},
		onLoad() {
			this.fetchData()
		},
		methods: {
			onReady() {
				this.$nextTick(() => {
					uni.createSelectorQuery().in(this).select(".scroll_content").boundingClientRect(res => {
						this.scrollHeight = this.deviceInfo.screenHeight - res.top
					}).exec()
				})
			},
			async fetchData() {
				if (this.loading == 'nomore')
					return
				this.loading = 'loading'
				const {
					todaygoods: {
						list,
						total
					}
				} = await this.$u.api.todayGoodsList(this.queryForm)
				this.total = total
				if (list.length) {
					this.list = this.list.concat(list)
				}



				if (list.length < this.queryForm.limit) {
					this.loading = 'nomore'
				} else {
					this.loading = 'loadmore'
				}
			},
			reloadData() {
				this.queryForm.page = 1
				this.loading = 'loadmore'
				this.list = []
				this.fetchData()
			},
			// 加载下一页
			lower() {
				if (this.loading == 'nomore')
					return
				this.queryForm.page++
				this.fetchData()
			},
		},
	}
</script>

<style lang="scss" scoped scoped>
	.header {
		width: 100%;
		height: 375rpx;
		position: relative;
		background-image: linear-gradient(to right, #C9E0FF 0%, #5BA1F6 100%);

		.bg {
			position: absolute;
			width: 100%;
			height: 100%;
			background-size: 100% 100%;
			background-repeat: no-repeat;
			background-position: 0 0;
		}

		&::after {
			content: "";
			background-color: #f5f7fa;
			width: 100%;
			height: 20rpx;
			position: absolute;
			bottom: 0;
			border-radius: 20rpx 20rpx 0 0;
			// transform: translateY(10rpx);
		}

		.content {
			position: absolute;
			top: 50rpx;
			left: 50rpx;
			display: flex;
			flex-direction: column;
			gap: 28rpx;

			.back {
				width: 88rpx;
				height: 88rpx;
				border-radius: 50%;
				font-size: 36rpx;
				display: flex;
				align-items: center;
				justify-content: center;
				color: #fff;
				background-color: rgba(255, 255, 255, .2);
			}

			.t1 {
				color: #fff;
				font-weight: bolder;
				font-size: 52rpx;
			}

			.t2 {
				color: #fff;
			}
		}
	}
</style>