<template>
	<view>
		<view class="list-box" v-if="list.length">
			<view class="list-item" v-for="item,index in list" :key="index" @click="handelItemClick(item)">
				<view class="img">
					<u-image :src="item.goods_img" height="150rpx" width="100%" border-radius="24rpx"></u-image>
				</view>
				<view class="right">
					<view class="name line2">{{item.goods_name}}</view>
					<view class="time">
						<template v-if="item.status_time > 0">
							{{ parseTime(item.status_time)}}
						</template>
						<template v-else>{{item.create_time}}</template>
					</view>
					<view class="other">
						<view class="price">
							<text class="now"><text class="money">￥</text>{{item.goods_price}}</text>
						</view>
						<view class="btn">销售</view>
					</view>
				</view>
			</view>
		</view>
		<template v-else>
			<view class="empty-data">
				<u-empty text="数据为空" mode="data"></u-empty>
			</view>
		</template>
	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {
			list: {
				type: Array,
				default: () => []
			},
		},
		data() {
			return {

			};
		},
		computed: {

		},
		watch: {

		},
		created() {

		},
		mounted() {

		},
		methods: {
			// 时间戳转日期
			parseTime(timestamp) {
				return this.$u.timeFormat(timestamp, 'yyyy-mm-dd hh:MM:ss')
			},
			// item点击
			handelItemClick(row) {
				this.$util.on('/pages/goods/detail?id='+row.id)
			},

		},
	};
</script>

<style scoped lang="scss" scoped>
	.list-box {
		display: flex;
		flex-direction: column;
		gap: 24rpx;
		padding: 20rpx;
		padding-top: 10rpx;

		.list-item {
			position: relative;
			display: flex;
			gap: 20rpx;
			background-color: #fff;
			padding: 20rpx;
			cursor: pointer;
			border-radius: 10px;
			
			.img{
				width: 150rpx;
			}
			.right{
				flex: 1;
				display: flex;
				flex-direction: column;
				justify-content: space-evenly;
				.name{
					font-weight: 500;
					font-size: 28rpx;
				}
				.time{
					color: #b6bac2;
					font-size: 24rpx;
				}
				.other{
					display: flex;
					.price{
						flex: 1;
						.now{
							color: #fd4d20;
							font-weight: bold;
							font-size: 36rpx;
							.money{
								font-size: 24rpx;
							}
						}
					}
					.btn{
						background: linear-gradient(90deg,#FE8A56 0%,#FF504B 100%);
						border-radius: 38rpx;
						padding: 5rpx 30rpx;
						font-size: 28rpx;
					}
				}
			}
		}
	}
</style>